/// NOTE: For commitment transactions, the precompile_input already contains the
/// RESOLVED absolute deadline. The detector resolved the offset for scheduled
/// transactions before creating the commitment. This returns the absolute deadline.
fn extract_max_poll_block_raw(precompile_input: &Bytes) -> Option<u64> {
    // Minimum length check: at least 7 * 32 = 224 bytes for first 7 fields
    if precompile_input.len() < 224 {
        debug!(
            target: "ritual::async_pool::extract_max_poll_block",
            input_len = precompile_input.len(),
            "Input too short to extract max_poll_block"
        );
        return None;
    }

    // Field 6 (max_poll_block/offset) is at offset 6 * 32 = 192 bytes
    let offset = 6 * 32;
    let max_poll_block_bytes = &precompile_input[offset..offset + 32];

    // Convert 32-byte slot to U256, then to u64
    let max_poll_block_u256 = U256::from_be_slice(max_poll_block_bytes);
    let raw_value = max_poll_block_u256.try_into().ok()?;

/// Represents the state of an async transaction in the pool.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum AsyncState {
    /// The SystemTx has been included in a canonical block, and we are waiting for
    /// the off-chain executor to provide the output.
    AwaitingExecution,
    /// The off-chain executor has provided the output and proof, and the async job is complete.
    Fulfilled,
    /// [Long-running only] Phase 1 settled, executor is polling for final result.
    /// The task ID has been finalized on-chain, now waiting for polling completion.
    AwaitingDelivery,
    /// [Long-running only] Polling complete, final result ready for Phase 2 delivery.
    DeliveryReady,
}

