/// Metadata for a transaction in the async pool.
/// This represents a pending async job that needs to be fulfilled.
#[derive(Debug, Clone)]
pub struct AsyncTxMeta<T: PoolTransaction> {
    /// The original user transaction (decoded from origin_tx_rlp).
    pub original_tx: OriginalTransaction,

    /// The system transaction (TxAsyncCommitment) that was created for async execution.
    /// None for direct async results that bypass system transactions.
    pub commitment_tx: Option<Arc<ValidPoolTransaction<T>>>,

    /// Address of the async precompile that was called.
    pub precompile_address: alloy_primitives::Address,

    /// Input data passed to the precompile.
    pub input: alloy_primitives::Bytes,

    /// The current state of the async transaction.
    pub state: AsyncState,

    /// Optional: The output/result from the off-chain executor (when fulfilled).
    /// For regular async: the final result

// Create metadata struct (avoid unnecessary clones)
// CRITICAL: Use precompile_input (raw parameters) NOT input (full tx data with selector)
// The executor signs over the precompile_input, so we must store that for signature
// verification

// For two-phase transactions (0x0805, 0x0806, 0x0818, 0x0819, 0x081A, 0x0820), compute Phase 2 deadline from offset.
// Field 6 in precompile input contains the Phase 2 deadline as an OFFSET from settlement block.
// The contract (AsyncJobTracker.markPhase1Settled) computes: phase2Deadline = settlementBlock + offset
//
// For pool purposes, we approximate with commit_block + offset. This is slightly conservative
// since commit_block <= settlement_block, so our computed deadline is slightly earlier than
// the contract's. This prevents the pool from considering a transaction as non-expired when
// the contract has already moved it to an expired bucket.
